    for obj in data:
        wrapped = {"_source": str(pth), "payload": obj}
        ndw.write(json.dumps(wrapped, ensure_ascii=False) + "\n")
        seen_objects += 1
else:
    wrapped = {"_source": str(pth), "payload": data}
    ndw.write(json.dumps(wrapped, ensure_ascii=False) + "\n")
    seen_objects += 1
```

