### Minimal Flask viewer (reads NDJSON, paginates, shows provenance)
Save as app.py next to merged.ndjson, then run `flask --app app run`:

```python
from flask import Flask, request, jsonify, render_template_string
import json, itertools

APP = Flask(__name__)
NDJSON_PATH = r"C:\Users\zoole\log_merge_output\merged.ndjson"

def iter_lines():
    with open(NDJSON_PATH, "r", encoding="utf-8") as f:
        for line in f:
            yield json.loads(line)

@APP.route("/api/records")
def records():
    page = int(request.args.get("page", 1))
    per = int(request.args.get("per", 50))
    start = (page-1)*per
    end = start + per
    it = itertools.islice(iter_lines(), start, end)
    return jsonify([r for r in it])

# simple UI for quick triage
TEMPLATE = """
<!doctype html>
<title>NDJSON Viewer</title>
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/mini.css/3.0.1/mini-default.min.css">
<div class="container">
  <h3>NDJSON Viewer</h3>
  <div id="list"></div>
  <button id="more">Load page</button>
</div>
<script>
let page=1;
async function load(){
  const res = await fetch('/api/records?page='+page+'&per=25');
  const arr = await res.json();
  if(!arr.length){ document.getElementById('more').disabled=true; return; }
  const list = document.getElementById('list');
  arr.forEach(o=>{
    const el = document.createElement('pre');
    el.style.border='1px solid #ddd';
    el.style.padding='8px';
    el.textContent = JSON.stringify(o, null, 2);
    list.appendChild(el);
  });
  page++;
}
document.getElementById('more').onclick = load;
load();
</script>
"""
@APP.route("/")
def ui():
    return render_template_string(TEMPLATE)
```

