  $rows += [PSCustomObject]@{
    path = $rel
    full = $full
    size = if ($f.size) { $f.size } else { "" }
    severity = if ($f.severity) { $f.severity } else { "Low" }
    matches = $f.matches
    snippet = $snippet
    isText = $isText
  }
}

# JSON-encode rows to embed into HTML safely
