.btn.secondary{background:#6c757d}
.small{font-size:0.9rem;color:#444}
.pill{padding:4px 8px;border-radius:10px;background:#f1f5f9}
.kv{font-weight:600;color:#222;margin-right:6px}
.footer{margin-top:12px;color:#666;font-size:0.9rem}
.checkbox{width:18px;height:18px}
.filterRow{display:flex;gap:8px;align-items:center;margin-top:10px;flex-wrap:wrap}
.pagination{display:flex;gap:6px;align-items:center;margin-top:8px}
.pageBtn{padding:6px 10px;border-radius:6px;background:#e9eefb;cursor:pointer}
"@

$js = @"
const rows = $rowsJson;
let filtered = rows.slice();
let sortKey = 'severity'; let sortAsc = false;
let page = 1; const pageSize = 25;

function severityScore(s){ if(s==='High') return 3; if(s==='Medium') return 2; return 1; }

function renderTable(){
  const tbody = document.getElementById('tb');
  tbody.innerHTML = '';
  const start = (page-1)*pageSize;
  const pageRows = filtered.slice(start, start+pageSize);
  for (const r of pageRows){
    const tr = document.createElement('tr');
    tr.innerHTML = `<td><input class='selectRow' type='checkbox' data-full='${encodeURIComponent(r.full)}'></td>
      <td><div class='pill'>${r.severity}</div></td>
      <td><code>${r.path}</code><div class='small'>${r.size} bytes</div></td>
      <td>${renderMatches(r.matches)}</td>
      <td><button class='btn' onclick='openFile("${encodeURIComponent(r.full)}")'>Open file</button>
          <button class='btn secondary' onclick='openFolder("${encodeURIComponent(r.full)}")'>Open folder</button>
          <button class='btn' onclick='togglePreview(this)'>Preview</button></td>`;
    tbody.appendChild(tr);
    // snippet row
    const sn = document.createElement('tr');
    sn.className='snippetRow';
    sn.style.display='none';
    sn.innerHTML = `<td colspan='5'><div class='row-snippet' data-path='${encodeURIComponent(r.full)}'>${r.snippet}</div></td>`;
    tbody.appendChild(sn);
  }
  document.getElementById('infoCount').textContent = filtered.length + ' flagged files';
  renderPagination();
}

function renderMatches(matches){
  let s='';
  for(const k in matches){
    const vals = matches[k] || [];
    const sample = vals.length? vals[0] : '';
    s += `<div><b>${k}</b>: ${vals.length} <div class='small'><pre>${escapeHtml(sample)}</pre></div></div>`;
  }
  return s;
}

function escapeHtml(t){ return (t+'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

function openFile(enc){ const p = decodeURIComponent(enc); window.open('file:///' + p); }
function openFolder(enc){ const p = decodeURIComponent(enc); const folder = p.replace(/\\[^\\]+$/,''); window.open('file:///' + folder); }

function togglePreview(btn){
  const tr = btn.closest('tr'); const nxt = tr.nextElementSibling;
  nxt.style.display = (nxt.style.display==='none')? 'table-row' : 'none';
}

function applyFilter(){
  const q = document.getElementById('q').value.toLowerCase();
  const sev = document.getElementById('severity').value;
  if(!q && sev==='All'){ filtered = rows.slice(); } else {
    filtered = rows.filter(r => {
      const matchQ = !q || r.path.toLowerCase().includes(q) || JSON.stringify(r.matches).toLowerCase().includes(q);
      const matchS = (sev==='All') || (r.severity === sev);
      return matchQ && matchS;
    });
  }
  page = 1; sortAndRender();
}

function sortAndRender(key){
  if(key){ if(sortKey===key) sortAsc = !sortAsc; else { sortKey=key; sortAsc=true; } }
  filtered.sort((a,b) => {
    if(sortKey==='severity'){ return sortAsc? severityScore(a.severity)-severityScore(b.severity) : severityScore(b.severity)-severityScore(a.severity); }
    if(a[sortKey] < b[sortKey]) return sortAsc? -1:1;
    if(a[sortKey] > b[sortKey]) return sortAsc? 1:-1;
    return 0;
  });
  renderTable();
}

function renderPagination(){
  const total = Math.max(1, Math.ceil(filtered.length / pageSize));
  document.getElementById('pageInfo').textContent = 'Page ' + page + ' / ' + total;
  const prev = document.getElementById('prevPg'); prev.disabled = (page<=1);
  const next = document.getElementById('nextPg'); next.disabled = (page>=total);
}

function gotoPrev(){ if(page>1) { page--; renderTable(); } }
function gotoNext(){ const total = Math.max(1, Math.ceil(filtered.length / pageSize)); if(page<total){ page++; renderTable(); } }

function selectAll(checked){ document.querySelectorAll('.selectRow').forEach(cb=>cb.checked=checked); }

function exportQuarantine(){
  const selected = Array.from(document.querySelectorAll('.selectRow')).filter(x=>x.checked).map(x=>decodeURIComponent(x.dataset.full));
  if(selected.length===0){ alert('No files selected'); return; }
  // create CSV content
  const csv = selected.map(p => '"' + p.replace(/"/g,'""') + '"').join('`n');
  const blob = new Blob([csv], {type:'text/csv'} );
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = 'fb_redflags_quarantine_list.csv'; document.body.appendChild(a); a.click(); URL.revokeObjectURL(url); a.remove();
  alert('Quarantine CSV downloaded. Run the provided PowerShell mover with that CSV to apply quarantine.');
}

function init(){
  document.getElementById('q').addEventListener('input', ()=>applyFilter());
  document.getElementById('severity').addEventListener('change', ()=>applyFilter());
  document.getElementById('selectAll').addEventListener('change', (e)=>selectAll(e.target.checked));
  document.getElementById('exportBtn').addEventListener('click', exportQuarantine);
  // header sorting
  document.getElementById('thSeverity').addEventListener('click', ()=>sortAndRender('severity'));
  document.getElementById('thPath').addEventListener('click', ()=>sortAndRender('path'));
  // initial render
  sortAndRender('severity');
}

window.addEventListener('DOMContentLoaded', init);
"@

# Build the HTML file
$html = @"
<!doctype html>
<html>
<head><meta charset='utf-8'><title>FB Redflags Fancy Overview</title><meta name='viewport' content='width=device-width,initial-scale=1'></head>
<body>
<div class='header'><h1>FB Redflags</h1><div class='controls'><span class='badge'>Report</span><div id='infoCount' class='small' style='margin-left:8px'></div></div></div>
<div class='filterRow'>
  <input id='q' placeholder='search path or match text' style='flex:1;padding:8px;border:1px solid #ccc;border-radius:8px' />
  <select id='severity' style='padding:8px;border-radius:6px'><option>All</option><option>High</option><option>Medium</option><option>Low</option></select>
  <label style='display:inline-flex;align-items:center;gap:6px'><input id='selectAll' type='checkbox' class='checkbox'/> Select all page</label>
  <button id='exportBtn' class='btn'>Export Quarantine CSV</button>
</div>
<table class='table' id='mainTable'>
<thead><tr><th></th><th id='thSeverity'>Severity</th><th id='thPath'>Path</th><th>Matches</th><th>Actions</th></tr></thead>
<tbody id='tb'></tbody>
</table>
<div class='pagination'><button id='prevPg' class='pageBtn' onclick='gotoPrev()'>Prev</button><div id='pageInfo' style='margin:0 8px'>Page</div><button id='nextPg' class='pageBtn' onclick='gotoNext()'>Next</button></div>
<div class='footer'>Actions: Open file uses file:/// links. Export Quarantine CSV downloads a CSV of selected absolute paths. Use the companion PowerShell mover to relocate files into quarantine safely.</div>
<script>$js</script>
</body>
</html>
"@

Set-Content -Path $outHtml -Value $html -Encoding UTF8
Start-Process $outHtml
Write-Host "Fancy overview written to $outHtml and opened in your browser."

# Create a small PowerShell quarantine mover to run after CSV export
$mover = @"
param([string]`$csv = '$quarantineCsv',[string]`$quarantineRoot = 'C:\Users\zoole\Desktop\fb_redflags_quarantine')

if (-not (Test-Path `$csv)) { Write-Host 'CSV not found:' `$csv; exit 1 }
New-Item -ItemType Directory -Path `$quarantineRoot -Force | Out-Null
`$paths = Get-Content `$csv | ForEach-Object { ($_ -replace '^\"|\"$','') }
foreach (`$p in `$paths) {
  if (-not (Test-Path `$p)) { Write-Host 'missing:' `$p; continue }
  try {
    `$rel = (Split-Path `$p -Leaf)
    `$dest = Join-Path `$quarantineRoot `$rel
    Move-Item -Path `$p -Destination `$dest -Force
    Write-Host 'moved:' `$p '->' `$dest
  } catch {
    Write-Host 'failed to move:' `$p $_.Exception.Message
  }
}
"@
Set-Content -Path $quarantineScript -Value $mover -Encoding UTF8
Write-Host "Quarantine mover script written to $quarantineScript"
```

Notes and small cautions
- The HTML embeds small snippets (up to 16KB) read server-side by PowerShell; those are sanitized for display and safe to open in your browser. No remote fetching is required.  
- file:/// will open files/folders in your default apps; some browsers may restrict file:// actions — run the HTML on the same machine that hosts the archive.  
- The quarantine mechanism is explicit: you select rows, export a CSV, then run the quarantine PowerShell mover to actually move files. That prevents accidental destructive actions initiated from the browser.  
- If you want inline “move now” buttons instead of export+run, I can build a tiny local web server that accepts signed requests and executes moves — but that requires running a local service (Flask or a light PowerShell HTTP listener). I avoided that for safety and portability.

