# PowerShell: generate HTML overview from scan report and open it
$Root = "C:\Users\zoole\Desktop\your_facebook_activity"
$Report = "C:\Users\zoole\Desktop\fb_redflags_report\redflags.json"
if (-not (Test-Path $Report)) { Write-Host "Report not found:" $Report; exit 1 }

$outHtml = Join-Path $env:TEMP "fb_redflags_overview.html"
$json = Get-Content -Path $Report -Raw | ConvertFrom-Json

$flags = if ($json.flags) { $json.flags } else { @() }
$generated = if ($json.generated) { $json.generated } else { (Get-Date).ToString("u") }
$rootLabel = if ($json.root) { $json.root } else { $Root }

# small inline CSS for readable table and badges
$css = @"
