.high{background:#f8d7da;color:#842029}
.med{background:#fff3cd;color:#664d03}
.low{background:#d1e7dd;color:#0f5132}
pre{white-space:pre-wrap;background:#fbfbfb;border:1px solid #eee;padding:8px;margin:6px 0}
a.button{display:inline-block;padding:6px 10px;background:#1f6feb;color:#fff;text-decoration:none;border-radius:6px;margin-right:6px}
.small{font-size:0.9rem;color:#444}
"@

# build rows
$rowsHtml = ""
foreach ($f in $flags) {
  $path = $f.path -replace '<','&lt;' -replace '>','&gt;'
  $size = if ($f.size) { $f.size } else { "" }
  $sev = if ($f.severity) { $f.severity } else { "Low" }
  $sevClass = switch ($sev) { "High" {"high"} "Medium" {"med"} default {"low"} }
