    $matchesHtml += "<div style='margin-bottom:6px'><b>$k</b>: $count &nbsp; <span class='small'>(sample)</span><div><pre>$sample</pre></div></div>"
  }

  $fileFull = Join-Path $Root $path
  $fileUrl = "file:///$fileFull"
  $folderUrl = "file:///" + (Split-Path $fileFull -Parent)

  $rowsHtml += "<tr><td><div class='badge $sevClass'>$sev</div></td><td><code>$path</code><div class='small'>$size bytes</div></td><td>$matchesHtml</td><td><a class='button' href='$fileUrl' target='_blank'>Open file</a><a class='button' style='background:#28a745' href='$folderUrl' target='_blank'>Open folder</a></td></tr>`n"
}

if ($rowsHtml -eq "") {
  $rowsHtml = "<tr><td colspan='4' class='small'>No flagged files in report.</td></tr>"
}

$html = @"
