<div class='meta'><span class='badge'>Report generated</span> <span class='small'>$generated</span> &nbsp; <span class='badge'>Archive root</span> <span class='small'>$rootLabel</span> &nbsp; <span class='badge'>Flagged files</span> <span class='small'>$(($flags).Count)</span></div>
<table>
<tr><th>Severity</th><th>Path</th><th>Matches</th><th>Actions</th></tr>
$rowsHtml
