### Scanner script (complete, ready to save as scan_fb_redflags.py)

Save this exact file to C:\Users\zoole\Desktop\your_facebook_activity\scan_fb_redflags.py (or overwrite your existing scanner). It is self-contained, uses chunked scanning with overlap, skips very large binaries, and writes a JSON report to C:\Users\zoole\Desktop\fb_redflags_report\redflags.json.

```python
#!/usr/bin/env python3
from pathlib import Path
from datetime import datetime, timezone
import json
import re
import sys

# === CONFIG ===
ROOT = Path(r"C:\Users\zoole\Desktop\your_facebook_activity")
OUT = Path(r"C:\Users\zoole\Desktop\fb_redflags_report")
OUT.mkdir(parents=True, exist_ok=True)

REPORT_PATH = OUT / "redflags.json"
CHUNK = 1024 * 1024   # 1 MiB
OVERLAP = 1024        # 1 KiB overlap
MAX_BYTES_SKIP = 50 * 1024 * 1024  # skip files larger than 50 MiB

# Precompiled patterns. Adjust or add patterns as needed.
PATTERNS = {
    "ssn": re.compile(r"\b(?!000|666|9\d{2})\d{3}[- ]?(?!00)\d{2}[- ]?(?!0000)\d{4}\b"),
    "credit_card": re.compile(r"\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14}|3[47][0-9]{13}|6(?:011|5[0-9]{2})[0-9]{12})\b"),
    "oauth_token_like": re.compile(r"\b(?:ya29\.[A-Za-z0-9_\-\.]{20,}|eyJ[0-9A-Za-z\-_\.]{40,})\b"),
    "email": re.compile(r"[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}"),
    "ip": re.compile(r"\b(?:\d{1,3}\.){3}\d{1,3}\b"),
    "phone": re.compile(r"\b(?:\+?1[\s\-\.\)]*)?(?:\(?\d{3}\)?[\s\-\.\)]*)?\d{3}[\s\-\.\)]*\d{4}\b"),
    "gps_coords": re.compile(r"[-+]?\d{1,3}\.\d+\s*,\s*[-+]?\d{1,3}\.\d+"),
    "dob_like": re.compile(r"\b(?:\d{1,2}[-/]\d{1,2}[-/]\d{2,4}|\d{4}-\d{2}-\d{2})\b"),
    "url": re.compile(r"https?://[^\s'\"<>]+"),
}

# Helper: choose order of severity (first patterns are higher severity)
SEV_ORDER = ["ssn", "credit_card", "oauth_token_like", "oauth_token_like", "oauth_token_like",
             "oauth_token_like", "oauth_token_like", "oauth_token_like", "oauth_token_like"]

# === REPORT skeleton ===
report = {
    "generated": datetime.now(timezone.utc).isoformat(),
    "root": str(ROOT),
    "flags": []
}

# === scanning utilities ===
def detect_binary(path: Path, sample_size: int = 4096) -> bool:
    try:
        with path.open("rb") as fh:
            chunk = fh.read(sample_size)
            if not chunk:
                return False
            # heuristic: NUL byte indicates binary
            if b"\x00" in chunk:
                return True
            # high non-text byte ratio
            nontext = sum(1 for b in chunk if b < 9 or (b > 13 and b < 32) or b > 126)
            return (nontext / max(1, len(chunk))) > 0.30
    except Exception:
        return True

def score_severity(found_keys):
    for k in SEV_ORDER:
        if k in found_keys:
            return "High"
    if found_keys:
        return "Medium"
    return "Low"

def scan_file(path: Path):
    try:
        size = path.stat().st_size
    except Exception:
        return
    if size == 0:
        return
    if size > MAX_BYTES_SKIP:
        print(f"skipping (too large): {path} ({size} bytes)")
        return
    if detect_binary(path):
        # skip obvious binaries (images, gifs, etc.)
        print(f"skipping (binary): {path}")
        return

    found = {}
    prev_tail = ""
    scanned = 0

    try:
        f = path.open("r", encoding="utf-8", errors="ignore")
    except Exception:
        print(f"skipping (cannot open text): {path}")
        return

    try:
        while True:
            chunk = f.read(CHUNK)
            if not chunk:
                break
            scanned += len(chunk)
            data = prev_tail + chunk

            for name, pat in PATTERNS.items():
                try:
                    for m in pat.finditer(data):
                        found.setdefault(name, []).append(m.group(0))
                except Exception as e:
                    # avoid catastrophic backtracking stalls
                    print(f"regex error {name} on {path}: {e}")
            # keep tail overlap
            if len(data) > OVERLAP:
                prev_tail = data[-OVERLAP:]
            else:
                prev_tail = data

            if scanned % (5 * CHUNK) == 0:
                print(f"scanned {scanned} bytes from {path}")

    except Exception as e:
        print(f"error scanning {path}: {e}")
    finally:
        try:
            f.close()
        except Exception:
            pass

    if found:
        flags_entry = {
            "path": str(path.relative_to(ROOT)),
            "size": size,
            "matches": {k: list(dict.fromkeys(v)) for k, v in found.items()},
            "severity": score_severity(found.keys())
        }
        report["flags"].append(flags_entry)
        print(f"flagged: {path} -> {flags_entry['severity']} ({len(flags_entry['matches'])} kinds)")

def scan():
    # walk files under ROOT
    count = 0
    for p in ROOT.rglob("*"):
        if p.is_file():
            count += 1
            if count % 200 == 0:
                print(f"files iterated: {count}")
            try:
                scan_file(p)
            except KeyboardInterrupt:
                print("interrupted by user")
                break
            except Exception as e:
                print(f"error scanning {p}: {e}")

if __name__ == "__main__":
    start = datetime.now(timezone.utc)
    print(f"scan started: {start.isoformat()}")
    scan()
    end = datetime.now(timezone.utc)
    report["summary"] = {
        "files_scanned_est": None,
        "flags_count": len(report["flags"]),
        "started": start.isoformat(),
        "finished": end.isoformat(),
        "duration_seconds": (end - start).total_seconds()
    }
    try:
        with REPORT_PATH.open("w", encoding="utf-8") as fh:
            json.dump(report, fh, indent=2, ensure_ascii=False)
        print(f"report written: {REPORT_PATH} ({len(report['flags'])} flagged files)")
    except Exception as e:
        print(f"failed to write report: {e}")
    sys.exit(0)
```

How to run
- From PowerShell (exit any Python REPL first):
  python "C:\Users\zoole\Desktop\your_facebook_activity\scan_fb_redflags.py"

What I changed and why (short)
- Chunked reads with overlap avoid long regex runs and huge memory use.
- Binary detection and large-file skip avoids stalls on media blobs.
- Multiple named regexes (PATTERNS) produce structured matches and severity.
- Writes a JSON report ready for the PowerShell or Flask navigator.

