### Option A — PowerShell-only local navigator (no Python)

This single PowerShell script reads your fb_redflags_report\redflags.json, builds a static HTML page that lists flagged files, shows match counts and context snippets, and opens the report in your default browser. It restricts file access to your archive root and does not require any external programs.

Copy the entire block and paste it into PowerShell (it’s ready-to-run):

```powershell
# Save as run_fb_flags_ps.ps1 or paste directly into PowerShell
$Root = "C:\Users\zoole\Desktop\your_facebook_activity"
$Report = "C:\Users\zoole\Desktop\fb_redflags_report\redflags.json"
$OutHtml = "$env:TEMP\fb_redflags_view.html"

if (-not (Test-Path $Report)) { Write-Host "Report not found:" $Report; exit 1 }

try {
  $json = Get-Content -Path $Report -Raw | ConvertFrom-Json
} catch {
  Write-Host "Failed to read/parse JSON:" $_.Exception.Message
  exit 1
}

function Get-ContextSnippet {
  param($fileRel, $match)
  $abs = Join-Path $Root $fileRel
  if (-not (Test-Path $abs)) { return "[file missing]" }
  try {
    $text = Get-Content -Path $abs -Raw -ErrorAction Stop
    $idx = $text.IndexOf($match)
    if ($idx -lt 0) { $idx = 0 }
    $start = [Math]::Max(0, $idx - 80)
    $len = [Math]::Min(200, $text.Length - $start)
    $snippet = $text.Substring($start, $len) -replace '<','&lt;' -replace '>','&gt;'
    return $snippet -replace "`r`n"," " -replace "`n"," "
  } catch {
    return "[unable to read]"
  }
}

# Severity helpers
$sevOrder = @("ssn","credit_card","oauth_token_like","oauth_token","ip","gps_coords","dob","url","email","phone")
function Score-Severity { param($matches)
  foreach ($k in $sevOrder) { if ($matches.PSObject.Properties.Name -contains $k) { return $k } }
  if ($matches -and $matches.PSObject.Properties.Count -gt 0) { return $matches.PSObject.Properties[0].Name }
  return "none"
}
function Sev-LabelClass { param($score)
  switch ($score) {
    "ssn" { return @("High","high") }
    "credit_card" { return @("High","high") }
    "oauth_token_like" { return @("High","high") }
    "oauth_token" { return @("Medium","med") }
    "ip" { return @("Medium","med") }
    "gps_coords" { return @("Medium","med") }
    "dob" { return @("Medium","med") }
    default { return @("Low","low") }
  }
}

# Build rows
$rows = @()
foreach ($item in $json.flags) {
  $rel = $item.path
  $matches = $item.matches
  $score = Score-Severity $matches
  $labelClass = Sev-LabelClass $score
  $ctx = @{}
  foreach ($prop in $matches.PSObject.Properties) {
    $val = $prop.Value
    if ($val -is [System.Array] -and $val.Count -gt 0) { $sample = $val[0] } else { $sample = $val }
    $ctx[$prop.Name] = Get-ContextSnippet -fileRel $rel -match ([string]$sample)
  }
  $rows += [PSCustomObject]@{ path=$rel; matches=$matches; score=$score; sev_label=$labelClass[0]; sev_class=$labelClass[1]; context=$ctx }
}

# Generate HTML
$html = @"
<!doctype html>
<html>
<head>
<meta charset='utf-8'/>
<title>FB Redflags Navigator</title>
<style>
body{font-family:Segoe UI,Arial;margin:18px;color:#111} table{border-collapse:collapse;width:100%} th,td{border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top} th{background:#f4f6f8}
.badge{display:inline-block;padding:3px 8px;border-radius:12px;background:#eee;color:#222;font-size:12px;margin-right:6px}
.high{background:#f8d7da;color:#842029}.med{background:#fff3cd;color:#664d03}.low{background:#d1e7dd;color:#0f5132}
pre{white-space:pre-wrap;background:#fbfbfb;border:1px solid #eee;padding:8px}
a.button{display:inline-block;padding:6px 10px;background:#1f6feb;color:#fff;text-decoration:none;border-radius:6px}
</style>
</head>
<body>
<h1>FB Redflags Navigator</h1>
<p><span class='badge'>Report</span> <span class='badge'>@([DateTime]::UtcNow.ToString("u"))</span> — <span class='badge'>@($rows.Count) flagged files</span></p>
<table>
<tr><th>Severity</th><th>Path</th><th>Matches</th><th>Context / Actions</th></tr>
"@

foreach ($r in $rows) {
  $matchesHtml = ""
  foreach ($p in $r.matches.PSObject.Properties) {
    $count = if ($p.Value -is [System.Array]) { $p.Value.Count } else { 1 }
    $matchesHtml += "<div><b>$($p.Name)</b>: $count match" + ($(if ($count -gt 1) {"es"} else {""})) + "</div>"
  }
  $ctxHtml = ""
  foreach ($c in $r.context.GetEnumerator()) {
    $ctxHtml += "<div style='margin-bottom:10px'><div style='font-weight:600'>$($c.Key)</div><pre>$($c.Value)</pre></div>"
  }
  # safe URL for view/download uses custom file URI scheme: open folder instead of serving raw content
  $fileFull = Join-Path $Root $r.path
  $fileFolder = Split-Path $fileFull -Parent
  $html += "<tr><td><div class='badge $($r.sev_class)'>$($r.sev_label)</div></td><td><code>$($r.path)</code></td><td>$matchesHtml</td><td>$ctxHtml<div><a class='button' href='file:///$fileFull' target='_blank'>Open file</a> <a class='button' style='background:#28a745' href='file:///$fileFolder' target='_blank'>Open folder</a></div></td></tr>"
}

$html += "</table><p style='margin-top:14px;color:#555'>Only files inside the archive root are referenced. Use Open file/Open folder to inspect originals.</p></body></html>"
Set-Content -Path $OutHtml -Value $html -Force -Encoding UTF8

Start-Process $OutHtml
Write-Host "Navigator written to $OutHtml and opened in your default browser."
```

Notes:
- The page uses file:/// links to open files/folders in Explorer (safe, local).  
- If a browser blocks file:// links, manually open the temp HTML path printed after the script runs.  
- This script does not modify any files.

