### Flagged-files navigator (overview)

Below is a complete, ready-to-run Flask app that presents all flagged files from your scanner (fb_redflags_report/redflags.json) in one navigable web UI. It shows severity, matched patterns, a context window around each match, and lets you view the original file contents safely from your local archive. Drop this file next to your scanner outputs and run it — nothing external, everything local.

---

### What it does
- Loads fb_redflags_report/redflags.json produced by your scanner.  
- Ranks severity (ssn / credit_card / oauth_token_like highest → email/phone/url lower).  
- Shows up to 10 flagged files with matches, each expandable to see match details and a 200-char context snippet.  
- Lets you view the full raw file (text files under TEXT_EXTS) or download any file from your archive.  
- Restricts file serving to the archive root to avoid accidental exposure outside your archive.

---

### Ready-to-run Flask app (save as fb_flags_viewer.py)

```python
# fb_flags_viewer.py
# Place this alongside C:\Users\zoole\Desktop\fb_redflags_report\redflags.json
# Run with: python "C:\Users\zoole\Desktop\your_facebook_activity\fb_flags_viewer.py"

from flask import Flask, render_template_string, jsonify, abort, send_file
from pathlib import Path
import json
import html
import mimetypes

ROOT = Path(r"C:\Users\zoole\Desktop\your_facebook_activity").resolve()  # archive root
REPORT = Path(r"C:\Users\zoole\Desktop\fb_redflags_report\redflags.json").resolve()
TEXT_EXTS = {".json", ".txt", ".html", ".htm", ".csv", ".js", ".xml", ".md"}

APP = Flask(__name__, static_folder=None)

TEMPLATE = """
<!doctype html>
<title>FB Redflags Navigator</title>
<style>
body {font-family:Segoe UI,Arial;margin:18px;color:#111}
h1 {margin-bottom:6px}
table {border-collapse:collapse;width:100%;margin-top:12px}
th,td {border:1px solid #ddd;padding:8px;text-align:left;vertical-align:top}
th {background:#f4f6f8}
.summary {margin-bottom:8px;color:#444}
.badge {display:inline-block;padding:3px 8px;border-radius:12px;background:#eee;color:#222;font-size:12px;margin-right:6px}
.high {background:#f8d7da;color:#842029}
.med {background:#fff3cd;color:#664d03}
.low {background:#d1e7dd;color:#0f5132}
pre {white-space:pre-wrap;background:#fbfbfb;border:1px solid #eee;padding:8px}
.details {font-size:13px;color:#222}
a.button {display:inline-block;padding:6px 10px;background:#1f6feb;color:#fff;text-decoration:none;border-radius:6px}
</style>
<h1>FB Redflags Navigator</h1>
<div class="summary"><span class="badge">Report</span> {{report_time}} — <span class="badge">{{count}} flagged files</span></div>
<table>
<tr><th>Severity</th><th>Path (relative)</th><th>Matches</th><th>Context / actions</th></tr>
{% for f in files %}
<tr>
  <td>
    <div class="badge {{f.sev_class}}">{{f.sev_label}}</div>
  </td>
  <td style="min-width:280px"><code>{{f.path}}</code></td>
  <td>
    {% for m,v in f.matches.items() %}
      <div class="details"><b>{{m}}</b>: {{v|length}} match{{'s' if v|length>1 else ''}}</div>
    {% endfor %}
  </td>
  <td>
    {% for m,ctx in f.context.items() %}
      <div style="margin-bottom:10px">
        <div style="font-weight:600">{{m}}</div>
        <pre>{{ctx}}</pre>
      </div>
    {% endfor %}
    <div>
      <a class="button" href="/view?path={{f.path_url}}">View file</a>
      <a class="button" href="/download?path={{f.path_url}}" style="background:#28a745">Download</a>
    </div>
  </td>
</tr>
{% endfor %}
</table>
<p style="margin-top:14px;color:#555">Only files inside the archive root are served. If a listed file cannot be viewed, it may be a binary or too large to render safely.</p>
"""

def load_report():
    if not REPORT.exists():
        return None
    data = json.loads(REPORT.read_text(encoding='utf-8', errors='ignore'))
    return data

SEV_ORDER = ("ssn", "credit_card", "oauth_token_like", "oauth_token", "ip", "gps_coords", "dob", "url", "email", "phone")

def score_severity(matches: dict):
    # simple severity: highest matching key in SEV_ORDER
    for key in SEV_ORDER:
        if key in matches:
            return key
    # fallback
    if matches:
        return next(iter(matches.keys()))
    return "none"

def severity_label_and_class(score):
    if score in ("ssn","credit_card","oauth_token_like"):
        return ("High", "high")
    if score in ("oauth_token","ip","gps_coords","dob"):
        return ("Medium", "med")
    return ("Low", "low")

def make_context_for_match(file_path: Path, raw_match):
    try:
        text = file_path.read_text(encoding='utf-8', errors='ignore')
    except Exception:
        return "[unable to read content]"
    idx = text.find(raw_match)
    if idx == -1:
        # try escaping/unescaping variants
        idx = 0
    start = max(0, idx - 100)
    end = min(len(text), idx + len(raw_match) + 100)
    snippet = text[start:end].replace('\r','')
    # show up to 200 chars, with match highlighted by surrounding brackets
    esc = html.escape(snippet)
    esc = esc.replace(html.escape(raw_match), ">>>"+html.escape(raw_match)+"<<<", 1)
    return esc[:1000]

@APP.route("/")
def index():
    rpt = load_report()
    if rpt is None:
        return "<p>Report not found at: {}</p>".format(REPORT)
    files = []
    for item in rpt.get("flags", []):
        rel = item.get("path")
        # Defensive: ensure path is str and resolved within ROOT
        try:
            abs_path = (ROOT / rel).resolve()
            if ROOT not in abs_path.parents and abs_path != ROOT:
                # skip anything outside root
                continue
        except Exception:
            continue
        matches = item.get("matches", {})
        score = score_severity(matches)
        label, cls = severity_label_and_class(score)
        # create small context dict (pattern -> snippet)
        ctx = {}
        for k, vals in matches.items():
            if isinstance(vals, list) and vals:
                ctx[k] = make_context_for_match(abs_path, str(vals[0]))
            else:
                ctx[k] = "[no preview]"
        files.append({
            "path": rel,
            "path_url": rel.replace("\\","/"),
            "matches": matches,
            "context": ctx,
            "sev_score": score,
            "sev_label": label,
            "sev_class": cls
        })
    # sort by severity then path
    files.sort(key=lambda x: (0 if x['sev_label']=="High" else 1 if x['sev_label']=="Medium" else 2, x['path']))
    return render_template_string(TEMPLATE, files=files, count=len(files), report_time=rpt.get("generated","unknown"))

@APP.route("/view")
def view_file():
    from flask import request
    rel = request.args.get("path", "")
    if not rel:
        abort(400)
    safe_rel = Path(rel)
    abs_path = (ROOT / safe_rel).resolve()
    if ROOT not in abs_path.parents and abs_path != ROOT:
        abort(403)
    if not abs_path.exists():
        abort(404)
    if abs_path.suffix.lower() not in TEXT_EXTS:
        return "<p>File is not a supported text type for inline viewing. Use Download to retrieve it.</p>"
    try:
        content = abs_path.read_text(encoding='utf-8', errors='ignore')
        safe = html.escape(content)
        return "<h3>Viewing: {}</h3><pre style='white-space:pre-wrap'>{}</pre>".format(html.escape(str(safe_rel)), safe)
    except Exception as e:
        return "<p>Unable to read file: {}</p>".format(html.escape(str(e)))

@APP.route("/download")
def download():
    from flask import request
    rel = request.args.get("path", "")
    if not rel:
        abort(400)
    safe_rel = Path(rel)
    abs_path = (ROOT / safe_rel).resolve()
    if ROOT not in abs_path.parents and abs_path != ROOT:
        abort(403)
    if not abs_path.exists():
        abort(404)
    # send_file will stream from disk; caller can save
    return send_file(str(abs_path), as_attachment=True, download_name=abs_path.name)

if __name__ == "__main__":
    print("Starting FB Redflags Navigator on http://127.0.0.1:5002")
    APP.run(debug=False, port=5002, host="127.0.0.1")
```

