### 📄 `collect_takeout_evidence.ps1`

```powershell
<#
.SYNOPSIS
  Collects forensic metadata from a suspected unauthorized Google Takeout folder.

.DESCRIPTION
  This script gathers file timestamps, scheduled tasks, security events, and environment info
  related to a Google Takeout archive. It is read-only and does not modify any files.

.PARAMETER TakeoutPath
  The root path of the Takeout folder. Defaults to:
  C:\Users\zoole\Desktop\takeout-20251030T060006Z-1-001\Takeout\

.OUTPUTS
  - takeout_file_timestamps.csv
  - takeout_scheduled_tasks.csv
  - takeout_security_events.json
  - takeout_logons.json
  - takeout_handles.txt (if handle.exe is available)
  - takeout_environment.txt
  - takeout_summary.txt

.REQUIREMENTS
  - Run as Administrator for full access to event logs and handle enumeration
  - Optional: Sysinternals handle.exe in PATH for open handle detection

.NOTES
  - This script does not upload, delete, or modify any files.
  - PII may be present in output files. Handle with care.
#>

param (
    [string]$TakeoutPath = "C:\Users\zoole\Desktop\takeout-20251030T060006Z-1-001\Takeout"
)

$desktop = [Environment]::GetFolderPath("Desktop")
$summary = @()
$timestampFormat = "yyyy-MM-dd hh:mm:ss tt"

function Write-Summary {
    param ($text)
    $summary += $text
    Write-Output $text
}

Write-Summary "=== Takeout Forensics Summary ==="
Write-Summary "Start Time: $(Get-Date -Format $timestampFormat)"
Write-Summary "Takeout Path: $TakeoutPath"

if (-Not (Test-Path $TakeoutPath)) {
    Write-Summary "ERROR: Takeout path not found. Exiting."
    return
}

# 1. File timestamps
try {
    $fileData = Get-ChildItem -Path $TakeoutPath -Recurse -File | Select-Object @{Name="FullName";Expression={$_.FullName}},
        @{Name="Length";Expression={$_.Length}},
        @{Name="CreationTime";Expression={$_.CreationTime.ToString($timestampFormat)}},
        @{Name="LastWriteTime";Expression={$_.LastWriteTime.ToString($timestampFormat)}},
        @{Name="LastAccessTime";Expression={$_.LastAccessTime.ToString($timestampFormat)}}
    $fileData | Export-Csv -Path "$desktop\takeout_file_timestamps.csv" -NoTypeInformation
    Write-Summary "✓ File timestamps collected."
} catch {
    Write-Summary "✗ Failed to collect file timestamps: $_"
}

# 2. Scheduled tasks
try {
    $tasks = Get-ScheduledTask | ForEach-Object {
        $info = Get-ScheduledTaskInfo -TaskName $_.TaskName -ErrorAction SilentlyContinue
        if ($info) {
            [PSCustomObject]@{
                TaskName = $_.TaskName
                LastRunTime = $info.LastRunTime.ToString($timestampFormat)
                NextRunTime = $info.NextRunTime.ToString($timestampFormat)
                LastTaskResult = $info.LastTaskResult
            }
        }
    }
    $tasks | Export-Csv -Path "$desktop\takeout_scheduled_tasks.csv" -NoTypeInformation
    Write-Summary "✓ Scheduled tasks collected."
} catch {
    Write-Summary "✗ Failed to collect scheduled tasks: $_"
}

# 3. Security events (File access)
try {
    $events = Get-WinEvent -FilterHashtable @{LogName='Security'; Id=4663; StartTime=(Get-Date).AddDays(-30)} -ErrorAction Stop |
        Where-Object { $_.Message -like "*$TakeoutPath*" }
    $events | ConvertTo-Json -Depth 5 | Out-File "$desktop\takeout_security_events.json"
    Write-Summary "✓ Security events (4663) collected."
} catch {
    Write-Summary "✗ Failed to collect security events (4663): $_"
}

# 4. Logon events (4624)
try {
    $logons = Get-WinEvent -FilterHashtable @{LogName='Security'; Id=4624; StartTime=(Get-Date).AddDays(-30)} -ErrorAction Stop |
        Where-Object { $_.Message -like "*$TakeoutPath*" }
    $logons | ConvertTo-Json -Depth 5 | Out-File "$desktop\takeout_logons.json"
    Write-Summary "✓ Logon events (4624) collected."
} catch {
    Write-Summary "✗ Failed to collect logon events (4624): $_"
}

# 5. LastAccessTime behavior
try {
    $fsutil = fsutil behavior query disablelastaccess 2>&1
    $fsutil | Out-File "$desktop\takeout_environment.txt"
    Write-Summary "✓ LastAccessTime behavior recorded."
} catch {
    Write-Summary "✗ Failed to query LastAccessTime behavior: $_"
}

# 6. Handle.exe (if available)
$handlePath = "handle.exe"
if (Get-Command $handlePath -ErrorAction SilentlyContinue) {
    try {
        & $handlePath $TakeoutPath > "$desktop\takeout_handles.txt"
        Write-Summary "✓ Open handles collected via handle.exe."
    } catch {
        Write-Summary "✗ handle.exe failed: $_"
    }
} else {
    Write-Summary "⚠ handle.exe not found in PATH. Skipping handle collection."
}

# 7. Final summary
Write-Summary "`nAll outputs saved to Desktop. Review takeout_summary.txt for details."
Write-Summary "End Time: $(Get-Date -Format $timestampFormat)"
Write-Summary "`nRecommended next steps:"
Write-Summary "- Review event logs for suspicious access."
Write-Summary "- Enable auditing if 4663 events are missing."
Write-Summary "- Use Procmon for live monitoring if needed."
Write-Summary "- Secure your Google Account and enable 2FA."

$summary | Out-File "$desktop\takeout_summary.txt"
```

