```python
import os, json
from datetime import datetime
from flask import Flask, render_template_string, send_file, request

# --- Configuration ---
ROOTS = [
    r"C:\Users\zoole",
    r"C:\Users\zoole\OneDrive",
    r"C:\Users\zoole\Google Drive",
    r"D:\\",
    r"E:\\"
]

MEDIA_TYPES = {
    "photos": [".jpg",".jpeg",".png",".gif",".bmp",".heic",".tiff",".tif",".webp",".raw",".cr2",".nef",".arw"],
    "videos": [".mp4",".mov",".avi",".mkv",".wmv",".flv",".mts",".m2ts",".3gp",".mpeg",".mpg"],
    "audio":  [".mp3",".wav",".flac",".aac",".ogg",".m4a",".aiff",".wma",".alac"],
    "other":  [".pdf",".doc",".docx",".xls",".xlsx",".ppt",".pptx",".txt",".csv",".md",".rtf"]
}

OUTFILE = r"C:\Users\zoole\system_map_media.json"

# --- Indexer ---
def index_media():
    all_media = {}
    for category, exts in MEDIA_TYPES.items():
        items = []
        for root in ROOTS:
            if os.path.exists(root):
                for dirpath, _, files in os.walk(root):
                    for fname in files:
                        ext = os.path.splitext(fname)[1].lower()
                        if ext in exts:
                            fpath = os.path.join(dirpath, fname)
                            try:
                                stat = os.stat(fpath)
                                items.append({
                                    "path": fpath,
                                    "basename": os.path.basename(fpath),
                                    "size_bytes": stat.st_size,
                                    "created": datetime.fromtimestamp(stat.st_ctime).isoformat(),
                                    "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
                                    "folder": dirpath,
                                    "category": category,
                                    "extension": ext
                                })
                            except Exception:
                                continue
        # Summaries
        by_year, by_month, by_ext, top_folders = {}, {}, {}, {}
        for f in items:
            year = f["created"][:4]
            month = f["created"][:7]
            by_year[year] = by_year.get(year,0)+1
            by_month[month] = by_month.get(month,0)+1
            by_ext[f["extension"]] = by_ext.get(f["extension"],0)+1
            top_folders[f["folder"]] = top_folders.get(f["folder"],0)+1

        top_folders = sorted(top_folders.items(), key=lambda x:x[1], reverse=True)[:5]
        total_size = sum(f["size_bytes"] for f in items)

        summary = {
            "total_files": len(items),
            "total_size_mb": round(total_size/1024/1024,2),
            "by_year": [{"year":k,"count":v} for k,v in sorted(by_year.items())],
            "by_month": [{"month":k,"count":v} for k,v in sorted(by_month.items())],
            "by_extension": [{"extension":k,"count":v} for k,v in sorted(by_ext.items(), key=lambda x:x[1], reverse=True)],
            "top_folders": [{"folder":k,"count":v} for k,v in top_folders]
        }
        all_media[category] = {"files": items, "summary": summary}

    global_summary = {
        "total_files_all": sum(all_media[c]["summary"]["total_files"] for c in all_media),
        "total_size_all_mb": round(sum(all_media[c]["summary"]["total_size_mb"] for c in all_media),2),
        "by_category": [
            {"category":c,
             "total_files": all_media[c]["summary"]["total_files"],
             "total_size_mb": all_media[c]["summary"]["total_size_mb"]}
            for c in all_media
        ]
    }

    final = {
        "generated": datetime.now().isoformat(),
        "roots": ROOTS,
        "media": all_media,
        "global": global_summary
    }

    with open(OUTFILE,"w",encoding="utf-8") as f:
        json.dump(final,f,indent=2)
    return final

# --- Flask App ---
app = Flask(__name__)
data = index_media()

TEMPLATE = """
<!doctype html>
<html>
<head>
  <title>System Map Media Gallery</title>
  <style>
    body { font-family: sans-serif; margin: 20px; background: #f9f9f9; }
    h1, h2 { color: #333; }
    .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 10px; }
    .item { background: white; padding: 10px; border: 1px solid #ccc; border-radius: 6px; box-shadow: 1px 1px 3px rgba(0,0,0,0.1); }
    .item:hover { transform: scale(1.05); transition: transform 0.2s ease; }
    img, video, audio { max-width: 100%; height: auto; display: block; margin: auto; }
    table { border-collapse: collapse; margin-bottom: 20px; }
    th, td { border: 1px solid #ccc; padding: 6px 10px; }
    th { background: #eee; }
    details { margin-bottom: 10px; }
  </style>
</head>
<body>
  <h1>System Map Media Gallery</h1>
  <h2>Global Summary</h2>
  <ul>
    <li>Total files: {{ data.global.total_files_all }}</li>
    <li>Total size (MB): {{ data.global.total_size_all_mb }}</li>
  </ul>

  <h3>By Category</h3>
  <table>
    <tr><th>Category</th><th>Files</th><th>Size (MB)</th></tr>
    {% for cat in data.global.by_category %}
      <tr><td>{{ cat.category }}</td><td>{{ cat.total_files }}</td><td>{{ cat.total_size_mb }}</td></tr>
    {% endfor %}
  </table>

  {% for cat, content in data.media.items() %}
    <h2>{{ cat|capitalize }} ({{ content.summary.total_files }})</h2>

    <details>
      <summary>Top Folders</summary>
      <ul>
        {% for folder in content.summary.top_folders %}
          <li>{{ folder.folder }} — {{ folder.count }} files</li>
        {% endfor %}
      </ul>
    </details>

    <details>
      <summary>Extensions</summary>
      <ul>
        {% for ext in content.summary.by_extension %}
          <li>{{ ext.extension }} — {{ ext.count }}</li>
        {% endfor %}
      </ul>
    </details>

    <div class="grid">
      {% for f in content.files[:50] %}
        <div class="item">
          {% if cat == "photos" %}
            <img src="/file?path={{ f.path }}">
          {% elif cat == "videos" %}
            <video controls src="/file?path={{ f.path }}"></video>
          {% elif cat == "audio" %}
            <audio controls src="/file?path={{ f.path }}"></audio>
          {% else %}
            <a href="/file?path={{ f.path }}">{{ f.basename }}</a>
          {% endif %}
        </div>
      {% endfor %}
    </div>
  {% endfor %}
</body>
</html>
"""

@app.route("/")
def gallery():
    return render_template_string(TEMPLATE, data=data)

@app.route("/file")
def serve_file():
    path = request.args.get("path")
    if os.path.exists(path):
        return send_file(path)
    return "File not found", 404

if __name__ == "__main__":
    app.run(debug=True)
