### Updated script (drop-in replacement)

```powershell
# === Comprehensive Media & File Indexer for System Map ===
# Scans user profile and common roots for photos, videos, audio, and documents
# Outputs a JSON file with raw metadata + summary stats, extension breakdowns, and source tracing

# Roots to scan
$roots = @(
    "C:\Users\zoole",
    "C:\Users\zoole\OneDrive",
    "C:\Users\zoole\Google Drive",
    "D:\",   # external drive (if exists)
    "E:\"    # SD card / USB (if exists)
)

# Extensions by category
$mediaTypes = @{
    photos = @("*.jpg","*.jpeg","*.png","*.gif","*.bmp","*.heic","*.tiff","*.tif","*.webp","*.raw","*.cr2","*.nef","*.arw")
    videos = @("*.mp4","*.mov","*.avi","*.mkv","*.wmv","*.flv","*.mts","*.m2ts","*.3gp","*.mpeg","*.mpg")
    audio  = @("*.mp3","*.wav","*.flac","*.aac","*.ogg","*.m4a","*.aiff","*.wma","*.alac")
    other  = @("*.pdf","*.doc","*.docx","*.xls","*.xlsx","*.ppt","*.pptx","*.txt","*.csv","*.md","*.rtf")
}

$allMedia = @{}

foreach ($category in $mediaTypes.Keys) {
    $exts = $mediaTypes[$category]
    $items = @()

    foreach ($root in $roots) {
        if (Test-Path $root) {
            foreach ($ext in $exts) {
                try {
                    Get-ChildItem -Path $root -Recurse -Include $ext -File -ErrorAction Stop | ForEach-Object {
                        $items += [PSCustomObject]@{
                            path        = $_.FullName
                            size_bytes  = $_.Length
                            created     = $_.CreationTime.ToString("o")
                            modified    = $_.LastWriteTime.ToString("o")
                            folder      = $_.DirectoryName
                            category    = $category
                            source_root = $root
                            extension   = $_.Extension.ToLower()
                        }
                    }
                } catch {
                    Write-Verbose "Skipped $root for $ext due to: $($_.Exception.Message)"
                }
            }
        }
    }

    # --- Build summary stats ---
    $byYear = $items | Group-Object { $_.created.Substring(0,4) } | Sort-Object Name | ForEach-Object {
        [PSCustomObject]@{ year = $_.Name; count = $_.Count }
    }

    $byMonth = $items | Group-Object { $_.created.Substring(0,7) } | Sort-Object Name | ForEach-Object {
        [PSCustomObject]@{ month = $_.Name; count = $_.Count }
    }

    $topFolders = $items | Group-Object folder | Sort-Object Count -Descending | Select-Object -First 5 | ForEach-Object {
        [PSCustomObject]@{ folder = $_.Name; count = $_.Count }
    }

    $byExtension = $items | Group-Object extension | Sort-Object Count -Descending | ForEach-Object {
        [PSCustomObject]@{ extension = $_.Name; count = $_.Count }
    }

    $totalSize = ($items | Measure-Object -Property size_bytes -Sum).Sum

    $summary = [PSCustomObject]@{
        total_files    = $items.Count
        total_size_mb  = [math]::Round($totalSize / 1MB, 2)
        by_year        = $byYear
        by_month       = $byMonth
        top_folders    = $topFolders
        by_extension   = $byExtension
    }

    $allMedia[$category] = [PSCustomObject]@{
        files   = $items
        summary = $summary
    }
}

# --- Global summary across all categories ---
$globalTotalFiles = 0
$globalTotalSizeMB = 0
$globalByCategory = @()

foreach ($cat in $allMedia.Keys) {
    $catSummary = $allMedia[$cat].summary
    $globalTotalFiles += $catSummary.total_files
    $globalTotalSizeMB += $catSummary.total_size_mb
    $globalByCategory += [PSCustomObject]@{
        category      = $cat
        total_files   = $catSummary.total_files
        total_size_mb = $catSummary.total_size_mb
    }
}

$globalSummary = [PSCustomObject]@{
    total_files_all    = $globalTotalFiles
    total_size_all_mb  = [math]::Round($globalTotalSizeMB, 2)
    by_category        = $globalByCategory
}

# --- Final JSON structure ---
$final = [PSCustomObject]@{
    generated = (Get-Date).ToString("o")
    roots     = $roots
    media     = $allMedia
    global    = $globalSummary
}

# Export to JSON
$outFile = "C:\Users\zoole\system_map_media.json"
$final | ConvertTo-Json -Depth 7 | Out-File $outFile -Encoding UTF8

Write-Host "Media index complete. Results saved to $outFile"
```

