```powershell
# === Media Indexer for System Map ===
# Scans user profile and common roots for photos, videos, and audio
# Outputs a JSON file with raw metadata + summary stats

# Roots to scan
$roots = @(
    "C:\Users\zoole",
    "C:\Users\zoole\OneDrive",
    "C:\Users\zoole\Google Drive",
    "D:\",   # external drive (if exists)
    "E:\"    # SD card / USB (if exists)
)

# Extensions by category
$mediaTypes = @{
    photos = @("*.jpg","*.jpeg","*.png","*.gif","*.bmp","*.heic","*.tiff")
    videos = @("*.mp4","*.mov","*.avi","*.mkv","*.wmv","*.flv")
    audio  = @("*.mp3","*.wav","*.flac","*.aac","*.ogg","*.m4a")
}

$allMedia = @{}

foreach ($category in $mediaTypes.Keys) {
    $exts = $mediaTypes[$category]
    $items = @()

    foreach ($root in $roots) {
        if (Test-Path $root) {
            foreach ($ext in $exts) {
                Get-ChildItem -Path $root -Recurse -Include $ext -ErrorAction SilentlyContinue | ForEach-Object {
                    $items += [PSCustomObject]@{
                        path       = $_.FullName
                        size_bytes = $_.Length
                        created    = $_.CreationTime.ToString("o")
                        modified   = $_.LastWriteTime.ToString("o")
                        folder     = $_.DirectoryName
                    }
                }
            }
        }
    }

    # --- Build summary stats ---
    $byYear = $items | Group-Object { $_.created.Substring(0,4) } | Sort-Object Name | ForEach-Object {
        [PSCustomObject]@{ year = $_.Name; count = $_.Count }
    }

    $byMonth = $items | Group-Object { $_.created.Substring(0,7) } | Sort-Object Name | ForEach-Object {
        [PSCustomObject]@{ month = $_.Name; count = $_.Count }
    }

    $topFolders = $items | Group-Object folder | Sort-Object Count -Descending | Select-Object -First 5 | ForEach-Object {
        [PSCustomObject]@{ folder = $_.Name; count = $_.Count }
    }

    $totalSize = ($items | Measure-Object -Property size_bytes -Sum).Sum

    $summary = [PSCustomObject]@{
        total_files   = $items.Count
        total_size_mb = [math]::Round($totalSize / 1MB, 2)
        by_year       = $byYear
        by_month      = $byMonth
        top_folders   = $topFolders
    }

    $allMedia[$category] = [PSCustomObject]@{
        files   = $items
        summary = $summary
    }
}

# --- Final JSON structure ---
$final = [PSCustomObject]@{
    generated = (Get-Date).ToString("o")
    media     = $allMedia
}

# Export to JSON
$outFile = "C:\Users\zoole\system_map_media.json"
$final | ConvertTo-Json -Depth 6 | Out-File $outFile -Encoding UTF8

Write-Host "Media index complete. Results saved to $outFile"
```

