Perfect—let’s **fold the summary stats directly into the JSON** so your system map has both the raw photo index *and* the aggregates in one file. That way TwinHelm (or any dashboard layer) can pull everything from a single source.

Here’s the updated PowerShell script:

```powershell
# Define roots to scan
$roots = @(
    "C:\Users\zoole\Pictures",
    "C:\Users\zoole\Downloads",
    "C:\Users\zoole\Desktop"
)

# Define extensions
$exts = @("*.jpg","*.jpeg","*.png","*.gif","*.bmp","*.heic")

$photoIndex = @()

foreach ($root in $roots) {
    if (Test-Path $root) {
        foreach ($ext in $exts) {
            Get-ChildItem -Path $root -Recurse -Include $ext -ErrorAction SilentlyContinue | ForEach-Object {
                $photoIndex += [PSCustomObject]@{
                    path       = $_.FullName
                    size_bytes = $_.Length
                    created    = $_.CreationTime.ToString("o")
                    modified   = $_.LastWriteTime.ToString("o")
                    folder     = $_.DirectoryName
                }
            }
        }
    }
}

# --- Build summary stats ---
# Count by year
$byYear = $photoIndex | Group-Object { $_.created.Substring(0,4) } | Sort-Object Name | ForEach-Object {
    [PSCustomObject]@{ year = $_.Name; count = $_.Count }
}

# Top 5 folders
$topFolders = $photoIndex | Group-Object folder | Sort-Object Count -Descending | Select-Object -First 5 | ForEach-Object {
    [PSCustomObject]@{ folder = $_.Name; count = $_.Count }
}

# Total stats
$summary = [PSCustomObject]@{
    total_photos = $photoIndex.Count
    by_year      = $byYear
    top_folders  = $topFolders
}

# --- Final JSON structure ---
$final = [PSCustomObject]@{
    photos  = $photoIndex
    summary = $summary
}

# Export to JSON
$outFile = "C:\Users\zoole\system_map_photos.json"
$final | ConvertTo-Json -Depth 5 | Out-File $outFile -Encoding UTF8

Write-Host "Indexed $($photoIndex.Count) photos into $outFile with summary stats"
```

