```python
from drivers.gemini_driver import ask_gemini
from drivers.copilot_driver import ask_copilot

def orchestrate(prompt: str, mode: str) -> str:
    if mode == "compare":
        g = ask_gemini(prompt)
        c = ask_copilot(prompt)
        return f"Gemini:\n{g}\n\nCopilot:\n{c}"

    if mode == "refine":
        draft = ask_gemini(prompt)
        return ask_copilot(f"Refine this for clarity and conciseness:\n\n{draft}")

    if mode == "collaborate":
        ideas = ask_gemini(f"Generate structured ideas for:\n\n{prompt}")
        return ask_copilot(f"Organize into an actionable plan:\n\n{ideas}")

    return f"[Unknown mode: {mode}]"
```

