#### Frontend: app.js
```javascript
const el = (id) => document.getElementById(id);

let stats = { count: 0, totalLen: 0, avgLen: 0 };

function updateStats(mode, text) {
  stats.count += 1;
  stats.totalLen += (text?.length || 0);
  stats.avgLen = Math.round(stats.totalLen / stats.count);
  el("statCount").textContent = stats.count;
  el("statMode").textContent = mode;
  el("statAvgLen").textContent = stats.avgLen;
}

async function runTask() {
  const prompt = el("prompt").value.trim();
  const mode = el("mode").value;
  if (!prompt) { el("status").textContent = "Enter a task first."; return; }
  el("status").textContent = "Thinking...";
  el("response").textContent = "";

  try {
    const res = await fetch("http://localhost:5000/task", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ prompt, mode })
    });
    const data = await res.json();
    const out = data.result || data.error || "No response.";
    el("response").textContent = out;
    updateStats(mode, out);
    el("status").textContent = "Done.";
    persistHistory(prompt, mode, out);
  } catch (e) {
    el("status").textContent = "Connection error.";
  }
}

function copyResponse() {
  const text = el("response").textContent;
  navigator.clipboard.writeText(text || "").then(() => {
    el("status").textContent = "Copied!";
    setTimeout(() => el("status").textContent = "", 800);
  });
}

function clearUI() {
  el("prompt").value = "";
  el("response").textContent = "";
  el("status").textContent = "";
}

function persistHistory(prompt, mode, result) {
  const item = { t: Date.now(), prompt, mode, result };
  const hist = JSON.parse(localStorage.getItem("twinhelm_hist") || "[]");
  hist.push(item);
  localStorage.setItem("twinhelm_hist", JSON.stringify(hist));
}

function toggleTheme() {
  const isLight = document.body.classList.toggle("light");
  el("themeToggle").textContent = isLight ? "Light" : "Dark";
}

el("runBtn").addEventListener("click", runTask);
el("copyBtn").addEventListener("click", copyResponse);
el("clearBtn").addEventListener("click", clearUI);
el("themeToggle").addEventListener("click", toggleTheme);
```

